<?php session_start(); if (!isset($_SESSION['user_id']) || $_SESSION['role'] != 'Admin') { header("Location: index.php"); exit(); } require_once 'config/database.php'; $success = ""; $error = ""; if ($_SERVER['REQUEST_METHOD'] == 'POST' && isset($_POST['add_user'])) { $email = $_POST['email']; $password = password_hash($_POST['password'], PASSWORD_DEFAULT); $role = $_POST['role']; $check = "SELECT * FROM users WHERE email = ?"; $stmt = $conn->prepare($check); $stmt->bind_param("s", $email); $stmt->execute(); if ($stmt->get_result()->num_rows == 0) { $insert = "INSERT INTO users (email, password, role) VALUES (?, ?, ?)"; $istmt = $conn->prepare($insert); $istmt->bind_param("sss", $email, $password, $role); if ($istmt->execute()) { $success = "User added!"; } } else { $error = "Email exists!"; } } if (isset($_GET['delete_user'])) { $id = $_GET['delete_user']; $del = "DELETE FROM users WHERE user_id = ?"; $stmt = $conn->prepare($del); $stmt->bind_param("i", $id); $stmt->execute(); $success = "User deleted!"; } $users = $conn->query("SELECT * FROM users ORDER BY created_at DESC"); $notifs = $conn->query("SELECT * FROM notifications ORDER BY created_at DESC"); $files = $conn->query("SELECT * FROM faculty_uploads ORDER BY uploaded_at DESC"); ?> <!DOCTYPE html><html><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"><title>Admin Dashboard</title><link rel="stylesheet" href="assets/css/style.css"></head><body><?php include 'includes/header.php'; ?><main class="container"><h1>Admin Dashboard</h1><?php if ($success) echo "<div class='alert alert-success'>$success</div>"; if ($error) echo "<div class='alert alert-error'>$error</div>"; ?><div class="card"><h2>Add New User</h2><form method="POST"><input type="email" name="email" class="form-input" placeholder="Email" required><input type="password" name="password" class="form-input" placeholder="Password" required><select name="role" class="form-input" required><option>Student</option><option>Faculty</option></select><button type="submit" name="add_user" class="btn btn-primary">Add User</button></form></div><div class="card"><h2>Manage Users</h2><table class="table"><tr><th>Email</th><th>Role</th><th>Date</th><th>Action</th></tr><?php while($u = $users->fetch_assoc()): ?><tr><td><?php echo $u['email']; ?></td><td><?php echo $u['role']; ?></td><td><?php echo date("M d", strtotime($u['created_at'])); ?></td><td><a href="?delete_user=<?php echo $u['user_id']; ?>" class="btn btn-danger btn-sm" onclick="return confirm('Sure?')">Delete</a></td></tr><?php endwhile; ?></table></div><div class="card"><h2>All Notifications</h2><?php while($n = $notifs->fetch_assoc()): ?><div><strong><?php echo $n['title']; ?></strong><p><?php echo $n['message']; ?></p></div><?php endwhile; ?></div><div class="card"><h2>All Files</h2><table class="table"><tr><th>Title</th><th>Uploaded By</th><th>Date</th></tr><?php while($file = $files->fetch_assoc()): ?><tr><td><?php echo $file['title']; ?></td><td><?php echo $file['uploaded_by']; ?></td><td><?php echo date("M d", strtotime($file['uploaded_at'])); ?></td></tr><?php endwhile; ?></table></div></main><?php include 'includes/footer.php'; ?></body></html>